- (void)addChildViewController:(UIViewController *)vc navTitle:(NSString *)navTitle tabTitle:(NSString *)tabTitle tabImage:(NSString *)tabImage {
    // 设置标题 - 由内至外设置的
    vc.title = navTitle;
    // 设置图像
    vc.tabBarItem.image = [[UIImage imageNamed:tabImage] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    vc.tabBarItem.selectedImage = [[UIImage imageNamed:[tabImage stringByAppendingString:@"选中"]] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
