    [self addChildViewController:navVc];
}

// 设置全局外观
- (void)setUpAppearence {
    [self setUpTabBar];
    [self setUpHUD];
}

- (void)setUpTabBar {
    // 设置tabBar的样式
    UITabBar *tabBar = self.tabBar;
    tabBar.translucent = NO;
    // 1> item选中时的渲染颜色
    tabBar.tintColor = RGB(64, 99, 231);
    // 2> item未选中时的渲染颜色
    if (@available(iOS 10.0, *)) {
        tabBar.unselectedItemTintColor = UIColorHex(666666);
    }
    if (@available(iOS 13.0, *)) {
        UITabBarAppearance *tabBarAppearence = [[UITabBarAppearance alloc] init];
        // 3> tabBar的颜色
        tabBarAppearence.backgroundColor = WBColorHex(0xF6F6F6);
        tabBar.standardAppearance = tabBarAppearence;
        if (@available(iOS 15.0, *)) {
            SEL sel = NSSelectorFromString(@"setScrollEdgeAppearance:");
            IMP imp = [tabBar methodForSelector:sel];
            void (*pFunc)(id, SEL, UITabBarAppearance *) = (void *)imp;
            pFunc(tabBar, sel, tabBarAppearence);
//            [tabBar performSelector:NSSelectorFromString(@"setScrollEdgeAppearance") withObject:tabBarAppearence];
//            tabBar.scrollEdgeAppearance = tabBarAppearence;
        }
    } else {
        // 3> tabBar的颜色
        tabBar.barTintColor = [UIColor whiteColor];
        // 4> 去除分割线
        tabBar.shadowImage = [UIImage new];
        tabBar.backgroundImage = [UIImage new];
    }
}

- (void)setUpHUD {
    [SVProgressHUD setBackgroundColor:RGBA(0, 0, 0, 0.5)];
    [SVProgressHUD setFont:[UIFont fontWithName:@"PingFang SC" size:14]];
    [SVProgressHUD setForegroundColor:[UIColor whiteColor]];
    [SVProgressHUD setMinimumSize:CGSizeMake(200, 120)];
    [SVProgressHUD setCornerRadius:15];
    [SVProgressHUD setMaximumDismissTimeInterval:0.8];
}


+ (void)presentVipPageFromPageSource:(NSString *)pageSource {
    UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];

    if ([rootVC isKindOfClass:[WBMainViewController class]]) {
        WBMainViewController *mainVC = (WBMainViewController *)rootVC;
        [mainVC presentVipPagePrivateFromPageSource:pageSource triggerId:nil];
    }
}

- (void)presentVipPagePrivateFromPageSource:(NSString *)pageSource triggerId:(nullable NSString *)triggerId {
    [WBEventManager logAppPageShowEvent:@"Vip" from:pageSource];
    WBVipViewController *vipVC = [[WBVipViewController alloc] initWithSource:pageSource triggerId:triggerId];
    UIViewController *presentedVC = self.presentedViewController;
    WBNavigationController *navVC = [[WBNavigationController alloc] initWithRootViewController:vipVC];
    navVC.modalPresentationStyle = UIModalPresentationFullScreen;
    if (presentedVC && [presentedVC isKindOfClass:[WBPopupViewController class]]) {
        [presentedVC dismissViewControllerAnimated:false completion:^{
            vipVC.dismissBlock = ^{
                [self presentViewController:presentedVC animated:false completion:nil];
            };
            [self presentViewController:navVC animated:YES completion:nil];
        }];
        return;
    }
    [self presentViewController:navVC animated:YES completion:nil];
}

+ (void)presentAdAwardsPage {
    UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];

    if ([rootVC isKindOfClass:[WBMainViewController class]]) {
        WBMainViewController *mainVC = (WBMainViewController *)rootVC;
        [mainVC presentAdAwardsPagePrivate];
    }
}

