// 如果选中的是是vip界面，让vip控制器以modal方式显示
- (BOOL)tabBarController:(UITabBarController *)tabBarController shouldSelectViewController:(UIViewController *)viewController {
    if ([self _checkIsVipPage:viewController]) {
        [self presentVipPagePrivateFromPageSource:@"tab" triggerId:nil];
        return NO;
    }
//    [WBEventManager logAppPageShowEvent:[NSStringFromClass(navVc.visibleViewController.class) substringWithRange:(NSRange){2,3}] from:@"tab"];
    return YES;
}

- (Boolean)_checkIsVipPage:(UIViewController *)vc {
    if (self.childViewControllers.count == 3) return false;
    return [self.childViewControllers indexOfObject:vc] == 1;
}

