// 一键启动开关 (首页/设置页复用)
- (void)toggleOneclickForVapp:(WBVAppModel *)vapp
                    presenter:(UIViewController *)presenter
                     setSwitch:(void(^)(BOOL on, BOOL animated))setSwitch {
    if (WBVAppManager.sharedManager.myApps.count <= 0) {
        if (setSwitch) setSwitch(NO, YES);
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"提醒" message:@"请先安装您的第一个应用后再来开启吧" preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
        [vc presentViewController:alert animated:YES completion:nil];
        return;
    }

    BOOL isTurningOn = !vapp.featureStatusInfo.isOneClickSwitchOn;
    BOOL canSwitch = [self handleSwitchBenefitFunction:WBUserBenefitOneClick target:isTurningOn vapp:vapp];
    if (!canSwitch) {
        if (setSwitch) setSwitch(NO, YES);
        return;
    }

    if (isTurningOn) {
        void (^successBlock)(void) = ^{
            NSUserDefaults *defaults = [NSUserDefaults standardUserDefaults];
            BOOL hasExecuted = [defaults boolForKey:@"Guide"];
            if (!hasExecuted) {
                WBOneClickStartGuidePageViewController *GuideVc = [WBOneClickStartGuidePageViewController new];
                NSMutableArray<WBVAppModel *> *apps = WBVAppManager.sharedManager.myApps;
                for (WBVAppModel *item in apps) { item.featureStatusInfo.isOneClickSwitchOn = NO; }
                vapp.featureStatusInfo.isOneClickSwitchOn = YES;
                [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                GuideVc.modalPresentationStyle = UIModalPresentationFullScreen;
                [presenter presentViewController:GuideVc animated:YES completion:^{}];
                [defaults setBool:YES forKey:@"Guide"];
                [defaults synchronize];
                if (setSwitch) setSwitch(YES, YES);
                [self consumeUsageOnceForBenefitBit:WBUserBenefitOneClick];
            } else {
                [WBNetworkManager.defaultManager connectOneClickisOn:YES callback:^(id _Nullable json, NSError *_Nullable error) {
                    if (error) {
                        [SVProgressHUD showErrorWithStatus:@"请检查网络连接"];
                        vapp.featureStatusInfo.isOneClickSwitchOn = NO;
                        [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                        if (setSwitch) setSwitch(NO, YES);
                    } else {
                        [SVProgressHUD showSuccessWithStatus:@"已开启一键启动"];
                        vapp.featureStatusInfo.isOneClickSwitchOn = YES;
                        [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                        if (setSwitch) setSwitch(YES, YES);
                        [self consumeUsageOnceForBenefitBit:WBUserBenefitOneClick];
                    }
                }];
            }
        };
        void (^failBlock)(void) = ^{ if (setSwitch) setSwitch(NO, YES); };

        if (vapp.featureStatusInfo.isLockSwitchOn) {
            WBPasswordViewController *passwordVc = [WBPasswordViewController new];
            passwordVc.firstSet = FALSE;
            passwordVc.vapp = vapp;
            passwordVc.type = WBPasswordViewControllerTypeEntry;
            passwordVc.successBlock = successBlock;
            passwordVc.failBlock = failBlock;
            [presenter.navigationController pushViewController:passwordVc animated:YES];
        } else {
            successBlock();
        }
    } else {
        void (^closeNetworkBlock)(void) = ^{
            [WBNetworkManager.defaultManager connectOneClickisOn:NO callback:^(id _Nullable json, NSError *_Nullable error) {
                if (error) {
                    [SVProgressHUD showErrorWithStatus:@"请检查网络连接"];
                    vapp.featureStatusInfo.isOneClickSwitchOn = YES;
                    [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                    if (setSwitch) setSwitch(YES, YES);
                } else {
                    vapp.featureStatusInfo.isOneClickSwitchOn = NO;
                    [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                    [SVProgressHUD showSuccessWithStatus:@"已关闭一键启动"];
                    if (setSwitch) setSwitch(NO, YES);
                }
            }];
        };
        if (vapp.featureStatusInfo.isLockSwitchOn) {
            WBPasswordViewController *passwordVc = [WBPasswordViewController new];
            passwordVc.firstSet = FALSE;
            passwordVc.vapp = vapp;
            passwordVc.type = WBPasswordViewControllerTypeEntry;
            passwordVc.successBlock = closeNetworkBlock;
            passwordVc.failBlock = ^{ if (setSwitch) setSwitch(YES, YES); };
            [presenter.navigationController pushViewController:passwordVc animated:YES];
        } else {
            closeNetworkBlock();
        }
    }

