lelele，先看这几段最关键的代码。

一是“一键启动”开关逻辑，在 [WBBenefitManager.m](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/Benefit/WBBenefitManager.m)：

```objc
// 一键启动开关 (首页/设置页复用)
- (void)toggleOneclickForVapp:(WBVAppModel *)vapp
                    presenter:(UIViewController *)presenter
                     setSwitch:(void(^)(BOOL on, BOOL animated))setSwitch {
    if (WBVAppManager.sharedManager.myApps.count <= 0) {
        if (setSwitch) setSwitch(NO, YES);
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"提醒" message:@"请先安装您的第一个应用后再来开启吧" preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
        [vc presentViewController:alert animated:YES completion:nil];
        return;
    }

    BOOL isTurningOn = !vapp.featureStatusInfo.isOneClickSwitchOn;
    BOOL canSwitch = [self handleSwitchBenefitFunction:WBUserBenefitOneClick target:isTurningOn vapp:vapp];
    if (!canSwitch) {
        if (setSwitch) setSwitch(NO, YES);
        return;
    }

    if (isTurningOn) {
        void (^successBlock)(void) = ^{
            NSUserDefaults *defaults = [NSUserDefaults standardUserDefaults];
            BOOL hasExecuted = [defaults boolForKey:@"Guide"];
            if (!hasExecuted) {
                WBOneClickStartGuidePageViewController *GuideVc = [WBOneClickStartGuidePageViewController new];
                NSMutableArray<WBVAppModel *> *apps = WBVAppManager.sharedManager.myApps;
                for (WBVAppModel *item in apps) { item.featureStatusInfo.isOneClickSwitchOn = NO; }
                vapp.featureStatusInfo.isOneClickSwitchOn = YES;
                [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                GuideVc.modalPresentationStyle = UIModalPresentationFullScreen;
                [presenter presentViewController:GuideVc animated:YES completion:^{}];
                [defaults setBool:YES forKey:@"Guide"];
                [defaults synchronize];
                if (setSwitch) setSwitch(YES, YES);
                [self consumeUsageOnceForBenefitBit:WBUserBenefitOneClick];
            } else {
                [WBNetworkManager.defaultManager connectOneClickisOn:YES callback:^(id _Nullable json, NSError *_Nullable error) {
                    if (error) {
                        [SVProgressHUD showErrorWithStatus:@"请检查网络连接"];
                        vapp.featureStatusInfo.isOneClickSwitchOn = NO;
                        [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                        if (setSwitch) setSwitch(NO, YES);
                    } else {
                        [SVProgressHUD showSuccessWithStatus:@"已开启一键启动"];
                        vapp.featureStatusInfo.isOneClickSwitchOn = YES;
                        [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:vapp];
                        if (setSwitch) setSwitch(YES, YES);
                        [self consumeUsageOnceForBenefitBit:WBUserBenefitOneClick];
                    }
                }];
            }
        };
```

你重点看这里：
- 首次引导分支里有这句：`for (WBVAppModel *item in apps) { item.featureStatusInfo.isOneClickSwitchOn = NO; }`
- 但后面的正常分支没有这段，只是直接把当前 `vapp` 设成 `YES`

二是启动时实际取哪个 vapp，在 [WBMainViewController.m](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/UI/Pages/Main/Controller/WBMainViewController.m)：

```objc
WBVAppModel *foundApp = [WBVAppManager.sharedManager.myApps filteredArrayUsingPredicate:
                             [NSPredicate predicateWithFormat:@"featureStatusInfo.isOneClickSwitchOn == YES"]
].firstObject;

BOOL isServerOneClickSupported = (WBSettingManager.sharedManager.Benefit & WBUserBenefitOneClick) != 0;
if (WBSettingManager.sharedManager.oneClickStart && isServerOneClickSupported) {
    if (foundApp && WBSettingManager.sharedManager.oneClickStart) {
        [WBHomeViewController msgTappedCheckAndLaunchVApp:foundApp.bundleId];
    }
}
```

这个意思很直接：
- 它只拿 `firstObject`
- 如果有多个 vapp 都是 `YES`，也只会启动第一个

三是保存逻辑，在 [WBVAppManager.m](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/WBVAppManager.m)：

```objc
- (void)saveOneClickStartStatusForVApp:(WBVAppModel *)vapp {
    [self saveMyApps];
}

- (void)saveMyApps {
    [[self.myApps modelToJSONObject] writeToFile:WBStorageManager.sharedManager.installedVAppListFilePath atomically:YES];
}
```

这个保存方法本身不处理互斥，只是把当前 `myApps` 整体落盘。

还有一段相关代码，是“开全局伪装时顺手关掉一键启动”，也在 [WBBenefitManager.m](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/Benefit/WBBenefitManager.m)：

```objc
NSMutableArray<WBVAppModel *> *apps = WBVAppManager.sharedManager.myApps;
for (WBVAppModel *item in apps) {
    item.featureStatusInfo.isOneClickSwitchOn = NO;
    [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:item];
}
```

所以现在的代码现状就是：
- 有“互斥”的意图
- 但只在首次引导和全局伪装那里做了
- 正常开启某个 vapp 的一键启动时，没有把其他 vapp 一并关掉

你要的话，我下一条就直接把“该怎么改、改哪几行最稳”给你列出来。

